import { useEffect, useState } from "react";
import api from "../api";

const PAGE_SIZE = 10;

export default function Customers() {
    const [rows, setRows] = useState([]);
    const [page, setPage] = useState(0);
    const [totalPages, setTotalPages] = useState(1);
    const [loading, setLoading] = useState(true);

    const [showModal, setShowModal] = useState(false);
    const [editing, setEditing] = useState(null); // row or null
    const [form, setForm] = useState({
        name: "", customerGroup: "NORMAL", region: "OTHER",
        address: "", contactPerson: "", phone: "", email: "", ownerId: ""
    });

    useEffect(()=>{ load(); }, [page]);

    function normalizeList(data){
        if(Array.isArray(data)) return { list:data, pages:1 };
        return { list: data?.content || [], pages: data?.totalPages || 1 };
    }

    async function load(){
        setLoading(true);
        try{
            const { data } = await api.get("/api/customers", { params:{ page, size: PAGE_SIZE }});
            const { list, pages } = normalizeList(data);
            setRows(list);
            setTotalPages(pages);
        }catch(e){
            console.error(e);
            setRows([]); setTotalPages(1);
        }finally{ setLoading(false); }
    }

    function openCreate(){
        setEditing(null);
        setForm({
            name:"", customerGroup:"NORMAL", region:"OTHER",
            address:"", contactPerson:"", phone:"", email:"", ownerId:""
        });
        setShowModal(true);
    }

    function openEdit(row){
        setEditing(row);
        setForm({
            name: row.name || "",
            customerGroup: row.customerGroup || "NORMAL",
            region: row.region || "OTHER",
            address: row.address || "",
            contactPerson: row.contactPerson || "",
            phone: row.phone || "",
            email: row.email || "",
            ownerId: row.ownerId || ""
        });
        setShowModal(true);
    }

    async function save(e){
        e.preventDefault();
        try{
            if(editing){
                await api.put(`/api/customers/${editing.id}`, form);
            }else{
                await api.post("/api/customers", form);
            }
            setShowModal(false);
            await load();
        }catch(err){
            alert(err?.response?.data?.message || "Lưu khách hàng thất bại");
        }
    }

    async function remove(row){
        if(!window.confirm(`Xoá khách hàng "${row.name}"?`)) return;
        try{
            await api.delete(`/api/customers/${row.id}`);
            await load();
        }catch(err){
            alert(err?.response?.data?.message || "Xoá khách hàng thất bại");
        }
    }

    return (
        <div className="space-y-4">
            <div className="flex items-center justify-between">
                <div>
                    <h2 className="text-lg font-semibold">Khách hàng</h2>
                    <p className="text-sm text-slate-500">Quản lý thông tin & phân loại</p>
                </div>
                <button onClick={openCreate} className="px-3 py-2 rounded-lg bg-indigo-600 text-white hover:bg-indigo-700">
                    Thêm khách hàng
                </button>
            </div>

            <div className="bg-white rounded-2xl border border-indigo-100 shadow overflow-hidden">
                <div className="overflow-auto">
                    <table className="min-w-full text-sm">
                        <thead className="bg-indigo-50 text-slate-600">
                        <tr>
                            <th className="px-4 py-3 text-left">Tên</th>
                            <th className="px-4 py-3 text-left">Nhóm</th>
                            <th className="px-4 py-3 text-left">Khu vực</th>
                            <th className="px-4 py-3 text-left">Địa chỉ</th>
                            <th className="px-4 py-3 text-left">Liên hệ</th>
                            <th className="px-4 py-3 text-left">Điện thoại</th>
                            <th className="px-4 py-3 text-left">Email</th>
                            <th className="px-4 py-3 text-right">Thao tác</th>
                        </tr>
                        </thead>
                        <tbody className="divide-y">
                        {loading ? (
                            <tr><td className="px-4 py-6" colSpan={8}>Đang tải…</td></tr>
                        ) : rows.length === 0 ? (
                            <tr><td className="px-4 py-6" colSpan={8}>Chưa có dữ liệu</td></tr>
                        ) : rows.map(c => (
                            <tr key={c.id} className="hover:bg-indigo-50/40">
                                <td className="px-4 py-3 font-medium">{c.name}</td>
                                <td className="px-4 py-3">{c.customerGroup}</td>
                                <td className="px-4 py-3">{c.region}</td>
                                <td className="px-4 py-3">{c.address || "-"}</td>
                                <td className="px-4 py-3">{c.contactPerson || "-"}</td>
                                <td className="px-4 py-3">{c.phone || "-"}</td>
                                <td className="px-4 py-3">{c.email || "-"}</td>
                                <td className="px-4 py-3 text-right">
                                    <div className="inline-flex gap-2">
                                        <button onClick={()=>openEdit(c)} className="px-2 py-1 rounded bg-indigo-50 text-indigo-700 hover:bg-indigo-100">Sửa</button>
                                        <button onClick={()=>remove(c)} className="px-2 py-1 rounded bg-rose-50 text-rose-700 hover:bg-rose-100">Xóa</button>
                                    </div>
                                </td>
                            </tr>
                        ))}
                        </tbody>
                    </table>
                </div>
            </div>

            {/* pagination */}
            <div className="flex gap-2">
                <button className="px-3 py-1.5 rounded bg-slate-100 disabled:opacity-50"
                        onClick={()=>setPage(p=>Math.max(0,p-1))} disabled={page<=0}>← Trước</button>
                <div className="px-3 py-1.5 text-sm">Trang {page+1}/{totalPages}</div>
                <button className="px-3 py-1.5 rounded bg-slate-100 disabled:opacity-50"
                        onClick={()=>setPage(p=>p+1)} disabled={page+1>=totalPages}>Sau →</button>
            </div>

            {/* modal */}
            {showModal && (
                <div className="fixed inset-0 z-40 bg-black/40 grid place-items-center p-4">
                    <div className="w-full max-w-2xl bg-white rounded-2xl shadow-xl border border-indigo-100">
                        <div className="p-5 border-b flex items-center justify-between">
                            <div className="font-semibold">{editing? "Sửa khách hàng" : "Thêm khách hàng"}</div>
                            <button className="text-slate-500 hover:text-slate-700" onClick={()=>setShowModal(false)}>Đóng</button>
                        </div>
                        <form onSubmit={save} className="p-5 grid grid-cols-1 md:grid-cols-2 gap-4">
                            <div>
                                <label className="text-sm text-slate-600">Tên</label>
                                <input
                                    required
                                    value={form.name}
                                    onChange={(e) => setForm(f => ({ ...f, name: e.target.value }))}
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                />
                            </div>

                            <div>
                                <label className="text-sm text-slate-600">Nhóm</label>
                                <select
                                    value={form.customerGroup}
                                    onChange={(e) => setForm(f => ({ ...f, customerGroup: e.target.value }))}
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                >
                                    <option value="VIP">VIP</option>
                                    <option value="POTENTIAL">Tiềm năng</option>
                                    <option value="NORMAL">Thường</option>
                                </select>
                            </div>

                            <div>
                                <label className="text-sm text-slate-600">Khu vực</label>
                                <select
                                    value={form.region}
                                    onChange={(e) => setForm(f => ({ ...f, region: e.target.value }))}
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                >
                                    <option value="NORTH">Miền Bắc</option>
                                    <option value="CENTRAL">Miền Trung</option>
                                    <option value="SOUTH">Miền Nam</option>
                                    <option value="OTHER">Khác</option>
                                </select>
                            </div>

                            {/* ĐÃ BỎ trường Liên hệ */}

                            <div>
                                <label className="text-sm text-slate-600">Điện thoại</label>
                                <input
                                    value={form.phone}
                                    onChange={(e) => setForm(f => ({ ...f, phone: e.target.value }))}
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                />
                            </div>

                            <div>
                                <label className="text-sm text-slate-600">Email</label>
                                <input
                                    type="email"
                                    value={form.email}
                                    onChange={(e) => setForm(f => ({ ...f, email: e.target.value }))}
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                />
                            </div>

                            <div className="md:col-span-2">
                                <label className="text-sm text-slate-600">Địa chỉ</label>
                                <input
                                    value={form.address}
                                    onChange={(e) => setForm(f => ({ ...f, address: e.target.value }))}
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                />
                            </div>

                            <div>
                                <label className="text-sm text-slate-600">Owner ID (tuỳ backend)</label>
                                <input
                                    value={form.ownerId || ""}
                                    onChange={(e) => setForm(f => ({ ...f, ownerId: e.target.value }))}
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                />
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
}
